#include <stdio.h>

long long fastPow(long long base, int exp) {
    long long result = 1;
    while (exp > 0) {
        if (exp & 1) result *= base;
        base *= base;
        exp >>= 1;
    }
    return result;
}

long long power(int base, int exponent) {
    if (exponent < 0) {
        return (base == 1) ? 1 : 0;
    }
    return fastPow(base, exponent);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int b, e;
        scanf("%d %d", &b, &e);
        printf("%lld\n", power(b, e));
    }
    return 0;
}

